using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // HasIndex removed — Cosmos DB throws at startup in EF Core 9.
        // Manage indexing via the Azure Portal or Bicep indexing policy.

        modelBuilder.Entity<Blog>(b =>
        {
            // Existing documents use "Discriminator"; EF Core 9 defaults to "$type".
            b.HasDiscriminator<string>("Discriminator");

            // Existing documents store id as "Blog|1"; EF Core 9 defaults to "1".
            b.HasRootDiscriminatorInJsonId(true);
        });
    }
}

